package com.chaobo.scm.supplier.application.account;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.common.integration.IamCollaborationApi;import com.chaobo.scm.supplier.application.integration.IntegrationCommandEnqueuer;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.account.SupplierAccessMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.List;
@Service public class SupplierAccessApplicationService{private final SupplierAccessMapper mapper;private final IdentifierGenerator ids;private final AuditLogRepository audit;private final TransactionalCommandExecutor executor;private final IntegrationCommandEnqueuer integrations;public SupplierAccessApplicationService(SupplierAccessMapper mapper,IdentifierGenerator ids,AuditLogRepository audit,TransactionalCommandExecutor executor,IntegrationCommandEnqueuer integrations){this.mapper=mapper;this.ids=ids;this.audit=audit;this.executor=executor;this.integrations=integrations;}@Transactional(readOnly=true)public List<SupplierContactView> contacts(long supplierId,CommandContext context){context.requirePermission("supplier:contact:view");context.requireSupplierScope(supplierId);return mapper.contacts(supplierId).stream().map(row->new SupplierContactView(row.id(),row.supplierId(),row.name(),row.mobile(),row.email(),row.role(),row.primary(),row.status(),row.version())).toList();}@Transactional(readOnly=true)public SupplierContactView contact(long id,CommandContext context){var row=mapper.contact(id);if(row==null)throw new BusinessException(ErrorCode.NOT_FOUND,"联系人不存在");context.requirePermission("supplier:contact:view");context.requireSupplierScope(row.supplierId());return new SupplierContactView(row.id(),row.supplierId(),row.name(),row.mobile(),row.email(),row.role(),row.primary(),row.status(),row.version());}@Transactional(readOnly=true)public List<SupplierUserBindingView> bindings(long supplierId,CommandContext context){context.requirePermission("supplier:account:view");context.requireSupplierScope(supplierId);return mapper.bindings(supplierId).stream().map(row->new SupplierUserBindingView(row.id(),row.supplierId(),row.userId(),row.role(),row.primary(),row.status(),row.boundAt(),row.version())).toList();}@Transactional public CommandResult saveContact(Long id,long supplierId,String name,String mobile,String email,String role,boolean primary,int version,CommandContext context){context.requirePermission("supplier:contact:manage");context.requireSupplierScope(supplierId);return executor.execute("supplier:contact",context,supplierId+name+mobile,()->{if(primary)mapper.clearPrimaryContact(supplierId);if(id==null){long newId=ids.nextId();mapper.insertContact(new SupplierAccessMapper.ContactRow(newId,supplierId,name,mobile,email,role,primary,1,0),context.operatorId());audit.save(context,"CREATE_CONTACT","SUPPLIER_CONTACT",newId,Long.toString(newId),null,"{\"primary\":"+primary+"}");return new CommandResult(newId,Long.toString(newId),1,"启用",0,null,false);}var old=mapper.contact(id);if(old==null)throw new BusinessException(ErrorCode.NOT_FOUND,"联系人不存在");if(old.version()!=version)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"联系人已更新");if(mapper.updateContact(new SupplierAccessMapper.ContactRow(id,supplierId,name,mobile,email,role,primary,1,version),version,context.operatorId())!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"联系人已更新");audit.save(context,"UPDATE_CONTACT","SUPPLIER_CONTACT",id,Long.toString(id),null,"{\"primary\":"+primary+"}");return new CommandResult(id,Long.toString(id),1,"启用",version+1,null,false);});}@Transactional public CommandResult bind(long supplierId,long userId,String role,boolean primary,CommandContext context){context.requirePermission("supplier:account:bind");context.requireSupplierScope(supplierId);return executor.execute("supplier:binding",context,supplierId+":"+userId,()->{if(mapper.activeBinding(supplierId,userId))throw new BusinessException(ErrorCode.STATE_CONFLICT,"用户已绑定该供应商");long id=ids.nextId();mapper.insertBinding(new SupplierAccessMapper.BindingRow(id,supplierId,userId,role,primary,1,null,0),context.operatorId());syncScope(userId,id,0,"绑定供应商账号");audit.save(context,"BIND_SUPPLIER_USER","SUPPLIER_USER_BINDING",id,Long.toString(id),null,"{\"userId\":"+userId+"}");return new CommandResult(id,Long.toString(id),1,"启用",0,null,false);});}@Transactional public CommandResult unbind(long id,int version,CommandContext context){context.requirePermission("supplier:account:bind");return executor.execute("supplier:binding",context,id+":"+version,()->{var binding=mapper.binding(id);if(binding==null)throw new BusinessException(ErrorCode.NOT_FOUND,"供应商用户绑定不存在");context.requireSupplierScope(binding.supplierId());if(binding.version()!=version||mapper.disableBinding(id,version)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"绑定已更新");syncScope(binding.userId(),id,version+1,"解除供应商账号");audit.save(context,"UNBIND_SUPPLIER_USER","SUPPLIER_USER_BINDING",id,Long.toString(id),null,"{\"status\":2}");return new CommandResult(id,Long.toString(id),2,"停用",version+1,null,false);});}private void syncScope(long userId,long bindingId,int version,String reason){integrations.enqueue("IAM_UPDATE_SUPPLIER_SCOPE","SUPPLIER_USER_BINDING",bindingId,version,"IAM",new IamCollaborationApi.UpdateSupplierScopeCommand("IAM-SCOPE-"+bindingId+"-"+version,userId,mapper.activeSupplierIds(userId),reason));}}
